class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        n = len(s)
        dp = [1] * n
        for i in range(1, n):
            if s[i] != s[i - 1]:
                dp[i] = dp[i - 1] + 1
            else:
                dp[i] = 1 if i == 1 else dp[i - 2] + 1
        return max(dp)
